77	fn lock_or_recover<'a, T>(mutex: &'a Mutex<T>, name: &'static str) -> MutexGuard<'a, T> {
78	    mutex.lock().unwrap_or_else(|poisoned| {
79	        tracing::warn!(mutex = name, "Recovering from poisoned gRPC bridge mutex");
80	        poisoned.into_inner()
81	    })
82	}
