173	    /// Submit a generate or embed request by passing a pre-built dict to Python.
174	    ///
175	    /// `req_type` is "generate", "embed", or "classify".
176	    /// `req_dict` contains fields matching GenerateReqInput or EmbeddingReqInput.
177	    pub fn submit_request(
178	        &self,
179	        rid: &str,
180	        req_type: &str,
181	        req_dict: HashMap<String, serde_json::Value>,
182	    ) -> PyResult<Receiver<ResponseChunk>> {
183	        let receiver = self.create_channel(rid)?;
184	        let rid_owned = rid.to_string();
185	
186	        let result = Python::with_gil(|py| -> PyResult<()> {
187	            let py_req_dict = json_map_to_pydict(py, &req_dict)?;
188	            let callback = self.make_chunk_callback(py, rid_owned)?;
189	
190	            let kwargs = PyDict::new(py);
191	            kwargs.set_item("req_type", req_type)?;
192	            kwargs.set_item("req_dict", py_req_dict)?;
193	            kwargs.set_item("chunk_callback", callback)?;
194	
195	            self.runtime_handle
196	                .call_method(py, "submit_request", (), Some(&kwargs))?;
197	            Ok(())
198	        });
199	
200	        match result {
201	            Ok(()) => Ok(receiver),
202	            Err(err) => {
203	                self.remove_channel(rid);
204	                Err(err)
205	            }
206	        }
207	    }
