213	    pub fn abort(&self, rid: &str, abort_all: bool) -> PyResult<()> {
214	        if !abort_all && rid.trim().is_empty() {
215	            return Err(PyValueError::new_err(
216	                "Abort requires a non-empty rid unless abort_all is true",
217	            ));
218	        }
219	
220	        let should_call_python = if abort_all {
221	            let mut state = lock_or_recover(self.state.as_ref(), "state");
222	            let rids = state
223	                .channels
224	                .drain()
225	                .map(|(rid, _)| rid)
226	                .collect::<Vec<_>>();
227	            let affected = rids.len();
228	            state.pending_sends.clear();
229	            state.ready_callbacks.clear();
230	            state.ready_signals.clear();
231	            for channel_rid in rids {
232	                state.terminal_errors.insert(
233	                    channel_rid.clone(),
234	                    TerminalError::Aborted { rid: channel_rid },
235	                );
236	            }
237	            tracing::debug!(affected, "gRPC abort_all cleared active response channels");
238	            true
239	        } else {
240	            let mut state = lock_or_recover(self.state.as_ref(), "state");
241	            let was_active = remove_channel_refs_locked(&mut state, rid);
242	            if was_active {
243	                state
244	                    .terminal_errors
245	                    .insert(rid.to_string(), TerminalError::Aborted { rid: rid.into() });
246	            } else {
247	                tracing::debug!(rid, "Ignoring abort for inactive gRPC request id");
248	            }
249	            was_active
250	        };
251	
252	        if !should_call_python {
253	            return Ok(());
254	        }
255	
256	        Python::with_gil(|py| {
257	            self.runtime_handle
258	                .call_method1(py, "abort", (rid, abort_all))?;
259	            Ok(())
260	        })
261	    }
