498	fn set_on_ready_for_rid(
499	    py: Python<'_>,
500	    rid: &str,
501	    state: &BridgeStateRef,
502	    on_ready: PyObject,
503	) -> PyResult<()> {
504	    let should_notify = {
505	        let mut state = lock_or_recover(state.as_ref(), "state");
506	        state
507	            .ready_callbacks
508	            .insert(rid.to_string(), on_ready.clone_ref(py));
509	        state.ready_signals.remove(rid)
510	    };
511	    if should_notify {
512	        on_ready.call0(py)?;
513	    }
514	    Ok(())
515	}
