517	fn clear_on_ready_for_rid(rid: &str, state: &BridgeStateRef) {
518	    // End notifications for this rid. Do not call set_on_ready again for the same rid.
519	    let mut state = lock_or_recover(state.as_ref(), "state");
520	    state.ready_callbacks.remove(rid);
521	    state.ready_signals.remove(rid);
522	}
